import java.util.Random;

public class Main {
    public static void main(String[] args) {
        System.out.println(getRandomOddNumber(new int[]{2, 4, 6})); // Test case with no odd numbers
        System.out.println(getRandomOddNumber(new int[]{1, 2, 3, 4, 5, 6})); // Test case with odd and even numbers
    }

    /**
     * Returns a random odd number from the given array.
     * If no odd number is found, returns 0.
     *
     * @param array The array to search for an odd number.
     * @return A random odd number from the array, or 0 if none found.
     */
    private static int getRandomOddNumber(int[] array) {
        int n = array.length;
        Random random = new Random();

        while (n > 0) {
            int idx = random.nextInt(n);

            // Check if the selected element is odd
            if (array[idx] % 2 != 0) {
                return array[idx];
            }

            // Swap the current element with the last unchecked element
            int temp = array[idx];
            array[idx] = array[n - 1];
            array[n - 1] = temp;

            // Decrease the range of elements to check
            n--;
        }

        // Return 0 if no odd number is found
        return 0;
    }
}

